import React from "react";

function Services() {
  return (
    <div className="services">
      <h1>Services</h1>
      <ul>
        <li>Portfolio & Project Development (React, HTML, CSS)</li>
        <li>Technical Documentation (SRS, Project Reports)</li>
        <li>Simple Applications & Webpages (XAML, basic JS)</li>
        <li>Support in Project Planning & Organization (Team Lead for SRS project)</li>
      </ul>
      <p>Currently learning and expanding skills in software development and web design.</p>
    </div>
  );
}

export default Services;
